import React, { useState, useEffect } from 'react';
import axios from 'axios';
import "./index.scss";
import AnimatedLetters from "../AnimatedLetters";
import API_BASE_URL from "../../config/api";
import { normalizePlayerListResponse } from "../../utils/playerList";

const TeamData = () => {
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [playerData, setPlayerData] = useState([]);
  const [playersToShow, setPlayersToShow] = useState(10);
  const [letterClass] = useState('text-animate');

  useEffect(() => {
    const params = new URLSearchParams(window.location.search);
    const teamValue = params.get('team');
    const nationValue = params.get('nation');
    const positionValue = params.get('position');
    const nameValue = params.get('name');

    const fetchData = async (query) => {
      try {
        const response = await axios.get(query);
        const { players, invalid, hint } = normalizePlayerListResponse(response.data);
        if (invalid) {
          setError(new Error(hint));
        }
        setPlayerData(players);
      } catch (err) {
        setError(err);
      } finally {
        setLoading(false);
      }
    };

    if (teamValue) {
      fetchData(`${API_BASE_URL}/api/v1/player?team=${encodeURIComponent(teamValue)}`);
    } else if (nationValue) {
      fetchData(`${API_BASE_URL}/api/v1/player?nation=${encodeURIComponent(nationValue)}`);
    } else if (positionValue) {
      fetchData(`${API_BASE_URL}/api/v1/player?position=${encodeURIComponent(positionValue)}`);
    } else if (nameValue) {
      fetchData(`${API_BASE_URL}/api/v1/player?name=${encodeURIComponent(nameValue)}`);
    } else {
      setLoading(false);
    }
  }, []);

  if (loading) {
    return <p>Loading...</p>;
  }

  if (error) {
    return <p>Error: {error.message}</p>;
  }

  return (
    <div className={`fade-in ${loading ? 'loading' : ''}`}>
      <div className="table-container">
        <h1 className="page-title">
          <AnimatedLetters letterClass={letterClass} strArray={"Player Data".split("")} idx={12} />
        </h1>
        <table>
          <thead>
            <tr>
              <th>Name</th>
              <th>Position</th>
              <th>Age</th>
              <th>Matches Played</th>
              <th>Starts</th>
              <th>Minutes Played</th>
              <th>Goals</th>
              <th>Assists</th>
              <th>Penalties Kicked</th>
              <th>Yellow Cards</th>
              <th>Red Cards</th>
              <th>Expected Goals (xG)</th>
              <th>Expected Assists (xAG)</th>
              <th>Team</th>
            </tr>
          </thead>
          <tbody>
            {(Array.isArray(playerData) ? playerData : [])
              .slice(0, playersToShow)
              .map((player, index) => (
              <tr key={player.id || `${player.name}-${index}`}>
                <td>{player.name}</td>
                <td>{player.pos}</td>
                <td>{player.age}</td>
                <td>{player.mp}</td>
                <td>{player.starts}</td>
                <td>{player.min}</td>
                <td>{player.gls}</td>
                <td>{player.ast}</td>
                <td>{player.pk}</td>
                <td>{player.crdy}</td>
                <td>{player.crdr}</td>
                <td>{player.xg}</td>
                <td>{player.xag}</td>
                <td>{player.team}</td>
              </tr>
            ))}
          </tbody>
        </table>
        {Array.isArray(playerData) && playersToShow < playerData.length && (
          <button
            onClick={() => setPlayersToShow(playersToShow + 10)}
            style={{ marginTop: '10px', marginBottom: '10px' }}
            className={`show-more-button ${loading ? 'loading' : ''}`}
          >
            Show More
          </button>
        )}
      </div>
    </div>
  );
};

export default TeamData;
